<?php
 namespace WPAICG\AutoGPT\Cron\Scheduler\Utils; if (!defined('ABSPATH')) { exit; } function get_current_cron_event_details_logic(string $hook, array $args): array { $timestamp = wp_next_scheduled($hook, $args); if ($timestamp === false) { return ['timestamp' => false, 'frequency' => null]; } $event_details = wp_get_scheduled_event($hook, $args, $timestamp); $frequency = $event_details ? $event_details->schedule : null; return ['timestamp' => $timestamp, 'frequency' => $frequency]; } 